1	import { useRef, useEffect, useCallback } from "react";
2	import { tokens } from "../tokens/tokens";
3	
4	type RotaryKnobProps = {
5	  value: number;
6	  min: number;
7	  max: number;
8	  step?: number;
9	  onChange: (value: number) => void;
10	  label: string;
11	  size?: number;
12	  valueText?: string;
13	};
14	
15	const START_ANGLE = 0.75 * Math.PI;
16	const END_ANGLE = 2.25 * Math.PI;
17	const ARC_RANGE = END_ANGLE - START_ANGLE;
18	const DRAG_SENSITIVITY = 200;
19	
20	function clamp(v: number, min: number, max: number): number {
21	  return Math.min(max, Math.max(min, v));
22	}
23	
24	function snapToStep(raw: number, step: number): number {
25	  return Math.round(raw / step) * step;
26	}
27	
28	function drawKnob(
29	  ctx: CanvasRenderingContext2D,
30	  size: number,
31	  ratio: number,
32	): void {
33	  const cx = size / 2;
34	  const cy = size / 2;
35	  const radius = size / 2 - tokens.border.width * 2;
36	
37	  ctx.clearRect(0, 0, size, size);
38	
39	  // Outer circle
40	  ctx.beginPath();
41	  ctx.arc(cx, cy, radius, 0, 2 * Math.PI);
42	  ctx.strokeStyle = tokens.color.gray700;
43	  ctx.lineWidth = tokens.border.width;
44	  ctx.stroke();
45	
46	  // Value arc
47	  const valueAngle = START_ANGLE + ratio * ARC_RANGE;
48	  ctx.beginPath();
49	  ctx.arc(cx, cy, radius, START_ANGLE, valueAngle);
50	  ctx.strokeStyle = tokens.color.blue;
51	  ctx.lineWidth = tokens.border.width + 1;
52	  ctx.lineCap = "round";
53	  ctx.stroke();
54	
55	  // Pointer line from center
56	  const pointerLen = radius * 0.7;
57	  const px = cx + Math.cos(valueAngle) * pointerLen;
58	  const py = cy + Math.sin(valueAngle) * pointerLen;
59	  ctx.beginPath();
60	  ctx.moveTo(cx, cy);
61	  ctx.lineTo(px, py);
62	  ctx.strokeStyle = tokens.color.white;
63	  ctx.lineWidth = tokens.border.width;
64	  ctx.lineCap = "round";
65	  ctx.stroke();
66	}
67	
68	export function RotaryKnob({
69	  value,
70	  min,
71	  max,
72	  step = 1,
73	  onChange,
74	  label,
75	  size = 48,
76	  valueText,
77	}: RotaryKnobProps): React.JSX.Element {
78	  const canvasRef = useRef<HTMLCanvasElement>(null);
79	  const listenersRef = useRef<AbortController | null>(null);
80	
81	  const ratio = max === min ? 0 : (value - min) / (max - min);
82	
83	  useEffect(() => {
84	    const canvas = canvasRef.current;
85	    if (!canvas) return;
86	    const ctx = canvas.getContext("2d");
87	    if (!ctx) return;
88	    drawKnob(ctx, size, ratio);
89	  }, [value, min, max, size, ratio]);
90	
91	  // Cleanup drag listeners on unmount
92	  useEffect(() => {
93	    return (): void => {
94	      listenersRef.current?.abort();
95	    };
96	  }, []);
97	
98	  const commit = useCallback(
99	    (next: number): void => {
100	      onChange(clamp(snapToStep(next, step), min, max));
101	    },
102	    [onChange, min, max, step],
103	  );
104	
105	  const handleKeyDown = useCallback(
106	    (e: React.KeyboardEvent): void => {
107	      switch (e.key) {
108	        case "ArrowUp":
109	        case "ArrowRight":
110	          e.preventDefault();
111	          commit(value + step);
112	          break;
113	        case "ArrowDown":
114	        case "ArrowLeft":
115	          e.preventDefault();
116	          commit(value - step);
117	          break;
118	        case "PageUp":
119	          e.preventDefault();
120	          commit(value + step * 10);
121	          break;
122	        case "PageDown":
123	          e.preventDefault();
124	          commit(value - step * 10);
125	          break;
126	        case "Home":
127	          e.preventDefault();
128	          commit(min);
129	          break;
130	        case "End":
131	          e.preventDefault();
132	          commit(max);
133	          break;
134	      }
135	    },
136	    [value, step, min, max, commit],
137	  );
138	
139	  const handlePointerDown = useCallback(
140	    (e: React.PointerEvent): void => {
141	      e.preventDefault();
142	      const target = e.target as HTMLElement;
143	      if (typeof target.setPointerCapture === "function") {
144	        target.setPointerCapture(e.pointerId);
145	      }
146	      const startY = e.clientY;
147	      const startValue = value;
148	      const range = max - min;
149	
150	      listenersRef.current?.abort();
151	      const controller = new AbortController();
152	      listenersRef.current = controller;
153	
154	      document.addEventListener(
155	        "pointermove",
156	        (moveEvent: PointerEvent) => {
157	          const delta = startY - moveEvent.clientY;
158	          const fraction = delta / DRAG_SENSITIVITY;
159	          commit(startValue + fraction * range);
160	        },
161	        { signal: controller.signal },
162	      );
163	
164	      document.addEventListener(
165	        "pointerup",
166	        () => {
167	          controller.abort();
168	        },
169	        { signal: controller.signal },
170	      );
171	    },
172	    [value, max, min, commit],
173	  );
174	
175	  return (
176	    <div
177	      role="slider"
178	      tabIndex={0}
179	      aria-valuemin={min}
180	      aria-valuemax={max}
181	      aria-valuenow={value}
182	      aria-valuetext={valueText}
183	      aria-label={label}
184	      onKeyDown={handleKeyDown}
185	      style={{
186	        display: "inline-flex",
187	        flexDirection: "column",
188	        alignItems: "center",
189	        gap: tokens.space[1],
190	        userSelect: "none",
191	      }}
192	    >
193	      <span
194	        style={{
195	          fontSize: tokens.text.xs,
196	          fontFamily: tokens.font.mono,
197	          color: tokens.color.gray300,
198	        }}
199	      >
200	        {label}
201	      </span>
202	      <canvas
203	        ref={canvasRef}
204	        width={size}
205	        height={size}
206	        onPointerDown={handlePointerDown}
207	        style={{ cursor: "grab" }}
208	      />
209	      <span
210	        style={{
211	          fontSize: tokens.text.xs,
212	          fontFamily: tokens.font.mono,
213	          color: tokens.color.white,
214	        }}
215	      >
216	        {value}
217	      </span>
218	    </div>
219	  );
220	}
