1	import { useCallback, useEffect, useMemo, useState } from "react";
2	import { Toolbar } from "./Toolbar";
3	import { ArrangementPanel } from "@ui/arrangement";
4	import { InstrumentPanel } from "./panels";
5	import { MixerPanel } from "./mixer";
6	import { MediaPoolPanel } from "./media-pool/MediaPoolPanel";
7	import { CommandRegistry } from "./keyboard/command-registry";
8	import { ShortcutMap } from "./keyboard/shortcut-map";
9	import { useKeyboardShortcuts } from "./keyboard/useKeyboardShortcuts";
10	import { useTransportShortcuts } from "./transport/useTransportShortcuts";
11	import { useSessionShortcuts } from "./session/useSessionShortcuts";
12	import { RecoveryDialog } from "./session/RecoveryDialog";
13	import { TransportProvider } from "@audio/transport-provider";
14	import { EffectsBridgeProvider } from "@audio/effects/EffectsBridgeProvider";
15	import { RoutingBridgeProvider } from "@audio/mixer/RoutingBridgeProvider";
16	import { useMediaPool } from "@audio/media-pool/use-media-pool";
17	import { sharedUndoManager } from "@state/undo/shared-undo-manager";
18	import { useSessionPersistence } from "@state/session/use-session-persistence";
19	import type { SessionStorage } from "@state/session/session-storage";
20	import { createDefaultSession } from "@state/session/session-schema";
21	import { hydrateStore } from "@state/session/use-session-persistence";
22	import { ErrorBoundary } from "./ErrorBoundary";
23	import { KeyboardShortcutsPanel } from "./keyboard/KeyboardShortcutsPanel";
24	
25	function DawShellInner({
26	  sessionStorage,
27	}: {
28	  sessionStorage: SessionStorage;
29	}): React.JSX.Element {
30	  const registry = useMemo(() => new CommandRegistry(), []);
31	  const shortcuts = useMemo(() => new ShortcutMap(), []);
32	  const pool = useMediaPool();
33	  const undoManager = sharedUndoManager;
34	  const { saveNow, recoveryWarnings } = useSessionPersistence(sessionStorage);
35	  const [dismissed, setDismissed] = useState(false);
36	  const [shortcutsOpen, setShortcutsOpen] = useState(false);
37	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
38	
39	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
40	
41	  useTransportShortcuts(registry, shortcuts);
42	  useSessionShortcuts(registry, shortcuts, undoManager, stableSaveNow);
43	
44	  useEffect(() => {
45	    registry.register({
46	      id: "app.shortcuts-legend",
47	      label: "Toggle Keyboard Shortcuts",
48	      execute: () => {
49	        setShortcutsOpen((prev) => !prev);
50	      },
51	    });
52	    shortcuts.bind({
53	      key: "?",
54	      shift: true,
55	      commandId: "app.shortcuts-legend",
56	    });
57	    return () => {
58	      registry.unregister("app.shortcuts-legend");
59	      shortcuts.unbind("app.shortcuts-legend");
60	    };
61	  }, [registry, shortcuts]);
62	
63	  useKeyboardShortcuts(registry, shortcuts);
64	
65	  return (
66	    <div
67	      data-testid="daw-shell"
68	      style={{
69	        display: "flex",
70	        flexDirection: "column",
71	        height: "100vh",
72	        backgroundColor: "var(--color-black)",
73	      }}
74	    >
75	      <Toolbar />
76	      <ErrorBoundary fallbackLabel="Panel crashed">
77	        <div
78	          style={{
79	            display: "flex",
80	            flexDirection: "column",
81	            flex: 1,
82	            overflow: "hidden",
83	          }}
84	        >
85	          <ArrangementPanel />
86	          <MixerPanel />
87	          <div style={{ display: "flex", overflow: "hidden" }}>
88	            <div style={{ flex: 1 }}>
89	              <InstrumentPanel />
90	            </div>
91	            <div style={{ flex: 1 }}>
92	              <MediaPoolPanel pool={pool} />
93	            </div>
94	          </div>
95	        </div>
96	      </ErrorBoundary>
97	      <KeyboardShortcutsPanel
98	        open={shortcutsOpen}
99	        onClose={() => {
100	          setShortcutsOpen(false);
101	        }}
102	      />
103	      <RecoveryDialog
104	        open={showRecovery}
105	        warnings={recoveryWarnings}
106	        onAccept={() => {
107	          setDismissed(true);
108	        }}
109	        onDiscard={() => {
110	          hydrateStore(createDefaultSession());
111	          setDismissed(true);
112	        }}
113	      />
114	    </div>
115	  );
116	}
117	
118	export function DawShell({
119	  sessionStorage,
120	}: {
121	  sessionStorage: SessionStorage;
122	}): React.JSX.Element {
123	  return (
124	    <TransportProvider>
125	      <EffectsBridgeProvider>
126	        <RoutingBridgeProvider>
127	          <DawShellInner sessionStorage={sessionStorage} />
128	        </RoutingBridgeProvider>
129	      </EffectsBridgeProvider>
130	    </TransportProvider>
131	  );
132	}
