        value={Math.round(pan * 100)}
        min={-100}
        max={100}
        step={1}
        onChange={handlePan}
        label="PAN"
        size={32}
      />

      <div className={styles["meter-fader-row"]}>
        <VuMeter
          level={meterLevel}
          peak={meterPeak}
          clip={clipping}
          width={8}
          height={96}
        />
        <Fader
          value={Math.round(volume * 100)}
          min={0}
          max={200}
          step={1}
          onChange={handleVolume}
          label=""
          height={96}
        />
      </div>

      <div className={styles["db-label"]}>{volumeToDb(volume)}</div>

      <div className={styles["controls-row"]}>
        <button
          className={
            muted ? (styles["btn-mute-active"] ?? "") : (styles["btn"] ?? "")
          }
          onClick={handleMute}
          aria-label={muted ? "Unmute" : "Mute"}
          type="button"
        >
          M
        </button>
        <button
          className={
            solo ? (styles["btn-solo-active"] ?? "") : (styles["btn"] ?? "")
          }
          onClick={handleSolo}
          aria-label={solo ? "Unsolo" : "Solo"}
          type="button"
        >
          S
        </button>
      </div>
    </div>
  );
}

