    render(<ClickToStart onStart={onStart} />);
    fireEvent.keyDown(screen.getByRole("button"), { key: "Enter" });
    expect(onStart).toHaveBeenCalledOnce();
  });

  it("calls onStart on Space key", () => {
    const onStart = vi.fn();
    render(<ClickToStart onStart={onStart} />);
    fireEvent.keyDown(screen.getByRole("button"), { key: " " });
    expect(onStart).toHaveBeenCalledOnce();
  });
});
